module adder_pipe_64bit(
    input clk,
    input rst_n,
    input [63:0] adda,
    input [63:0] addb,
    input i_en,
    output [63:0] result,
    output o_en
);

reg [63:0] reg_adda, reg_addb;
reg [1:0] state;
reg [63:0] sum;
reg valid;

localparam IDLE = 2'b00;
localparam STAGE1 = 2'b01;
localparam STAGE2 = 2'b10;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        reg_adda <= 64'b0;
        reg_addb <= 64'b0;
        state <= IDLE;
        valid <= 1'b0;
    end else begin
        case (state)
            IDLE: begin
                if (i_en) begin
                    reg_adda <= adda;
                    reg_addb <= addb;
                    state <= STAGE1;
                end
            end
            STAGE1: begin
                sum <= reg_adda + reg_addb;
                state <= STAGE2;
            end
            STAGE2: begin
                valid <= 1'b1;
                state <= IDLE;
            end
        endcase
    end
end

assign result = sum;
assign o_en = valid;

endmodule
